script.text:
      /* <flatten type="Javascript"> */
function active$CarriedForwardAnnualLeave(f) {
  f.add_onResponseComplete(on$CarriedForwardAnnualLeave$ResponseComplete);
  scatter$CarriedForwardAnnualLeave(f);
}
function scatter$CarriedForwardAnnualLeave(f) {if (f._action == 'New') f.setItemValue('nam_hl', (new Date).getFullYear());}
function close$CarriedForwardAnnualLeave(f) {try {f.remove_onResponseComplete(on$CarriedForwardAnnualLeave$ResponseComplete)} catch (ex) {}}
function on$CarriedForwardAnnualLeave$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, id = f.get_id();
  switch (context) {
    case 'Checking':
      var m = f.getItemValue('thang'), d = f.getItemValue('ngay'), v = f._language == 'v';
      if (m == 0 && d == 0) break;
      if (m < 1 || m > 12) {
        var e = (v ? 'Trường <span class="Highlight">Tháng giới hạn</span> chưa nhập hoặc giá trị nhập không hợp lệ.' : 'Field <span class="Highlight">Due Month</span> must not be blank or has invalid value.');
        $func.hideWait(id);
        $message.show(e, String.format('$find(\'{0}\').getItem(\'thang\').focus()', id));
        f._checked = false;
        break;
      }

      if ((d < 1) || (d > 31) || (m == 2 && d > 29) || ((m == 4 || m == 6 || m == 9 || m == 11) && d > 30)) {
        var e = (v ? 'Trường <span class="Highlight">Ngày giới hạn</span> chưa nhập hoặc giá trị nhập không hợp lệ.' : 'Field <span class="Highlight">Due Day</span> must not be blank or has invalid value.');
        $func.hideWait(id);
        $message.show(e, String.format('$find(\'{0}\').getItem(\'ngay\').focus()', id));
        f._checked = false;
        break;
      }
      break;

    default:
      break;
  }
}
/* </flatten> */
